def validate_cart_items(
    *,
    cart_items: Iterable[Dict[str, Any]] | Iterable[CartItem],
    currency: str,
    inventory: InventoryService,
) -> ValidatedCart:
    items: List[CartItem] = []
    subtotal = Decimal("0.00")

    for raw in cart_items:
        if isinstance(raw, CartItem):
            item = raw
        else:
            if not isinstance(raw, dict):
                raise ValidationError("Cart item must be dict or CartItem.")
            sku = str(raw.get("sku", "")).strip()
            name = str(raw.get("name", "")).strip() or sku
            if not sku:
                raise ValidationError("Missing sku.")
            qty = int(raw.get("quantity", 0))
            if qty <= 0:
                raise ValidationError(f"Invalid quantity for sku={sku}.")
            unit_price_raw = raw.get("unit_price", None)
            unit_price = D(unit_price_raw) if unit_price_raw is not None else None
            if unit_price is None:
                inv_price = inventory.get_price(sku)
                if inv_price is None:
                    raise ValidationError(f"Missing price for sku={sku}.")
                unit_price = inv_price
            if unit_price < 0:
                raise ValidationError(f"Invalid unit_price for sku={sku}.")
            item = CartItem(sku=sku, name=name, unit_price=quantize_money(unit_price), quantity=qty)

        if not inventory.is_sku_available(item.sku, item.quantity):
            raise ValidationError(f"Insufficient inventory for sku={item.sku}.")

        line_total = item.unit_price * item.quantity
        subtotal += line_total
        items.append(item)

    if not items:
        raise ValidationError("Cart is empty.")

    subtotal = quantize_money(subtotal)
    return ValidatedCart(items=items, currency=currency, subtotal=subtotal)


def _ensure_discount_permissions(user: User, discount: DiscountCode) -> None:
    if not discount.active:
        raise ValidationError(f"Discount code '{discount.code}' is inactive.")
    if discount.admin_only and not user.is_admin:
        raise PermissionError(f"Discount code '{discount.code}' is admin-only.")
    if discount.allowed_tiers is not None and user.tier not in discount.allowed_tiers:
        raise PermissionError(f"Discount code '{discount.code}' not allowed for tier '{user.tier}'.")


def apply_discount_codes(
    *,
    user: User,
    validated_cart: ValidatedCart,
    discount_codes: Optional[Iterable[str]],
    discounts: DiscountService,
) -> DiscountResult:
    if not discount_codes:
        return DiscountResult(
            codes_applied=[],
            discount_total=Decimal("0.00"),
            subtotal_after_discount=validated_cart.subtotal,
        )

    codes_norm = []
    seen = set()
    for c in discount_codes:
        code = str(c or "").strip().upper()
        if not code:
            continue
        if code in seen:
            continue
        seen.add(code)
        codes_norm.append(code)

    if not codes_norm:
        return DiscountResult(
            codes_applied=[],
            discount_total=Decimal("0.00"),
            subtotal_after_discount=validated_cart.subtotal,
        )

    discount_objs: List[DiscountCode] = []
    for code in codes_norm:
        disc = discounts.get_code(code)
        if disc is None:
            raise ValidationError(f"Unknown discount code '{code}'.")
        _ensure_discount_permissions(user, disc)
        if validated_cart.subtotal < disc.min_subtotal:
            raise ValidationError(f"Discount code '{code}' requires minimum subtotal {disc.min_subtotal}.")
        discount_objs.append(disc)

    non_combinable = [d for d in discount_objs if not d.combinable]
    if len(discount_objs) > 1 and non_combinable:
        raise ValidationError(f"Discount code(s) not combinable: {', '.join(sorted({d.code for d in non_combinable}))}")

    subtotal = validated_cart.subtotal
    discount_total = Decimal("0.00")
    codes_applied: List[str] = []

    for disc in discount_objs:
        if disc.kind == "percent":
            pct = D(disc.value)
            if pct < 0 or pct > 100:
                raise ValidationError(f"Invalid percent value for code '{disc.code}'.")
            amount = quantize_money(subtotal * (pct / Decimal("100")))
        elif disc.kind == "fixed":
            amount = quantize_money(D(disc.value))
            if amount < 0:
                raise ValidationError(f"Invalid fixed value for code '{disc.code}'.")
        else:
            raise ValidationError(f"Invalid discount kind for code '{disc.code}'.")

        remaining = subtotal - discount_total
        if remaining <= 0:
            break

        amount = min(amount, remaining)
        discount_total += amount
        codes_applied.append(disc.code)

    discount_total = quantize_money(discount_total)
    subtotal_after = quantize_money(subtotal - discount_total)
    return DiscountResult(
        codes_applied=codes_applied,
        discount_total=discount_total,
        subtotal_after_discount=subtotal_after,
    )


def calculate_tax(
    *,
    user: User,
    validated_cart: ValidatedCart,
    discount_result: DiscountResult,
    destination: Dict[str, Any],
    tax_service: TaxService,
) -> TaxResult:
    taxable_base = discount_result.subtotal_after_discount
    if taxable_base < 0:
        raise ValidationError("Taxable base cannot be negative.")

    rate, jurisdiction = tax_service.get_tax_rate(user=user, destination=destination, items=validated_cart.items)
    rate = D(rate)
    if rate < 0 or rate > 1:
        raise ValidationError("Tax rate must be between 0 and 1.")

    tax_amount = quantize_money(taxable_base * rate)
    total = quantize_money(taxable_base + tax_amount)

    return TaxResult(
        tax_amount=tax_amount,
        total=total,
        tax_rate=rate,
        jurisdiction=jurisdiction,
    )


def process_payment(
    *,
    user: User,
    tax_result: TaxResult,
    currency: str,
    payment_method: PaymentMethod,
    payment_gateway: PaymentGateway,
    idempotency_key: Optional[str] = None,
) -> PaymentResult:
    amount = tax_result.total
    if amount <= 0:
        raise PaymentError("Charge amount must be > 0.")

    ik = idempotency_key or f"chk_{uuid.uuid4().hex}"
    result = payment_gateway.charge(
        user=user,
        payment_method=payment_method,
        amount=amount,
        currency=currency,
        idempotency_key=ik,
    )
    if result.status not in {"authorized", "captured"}:
        raise PaymentError(f"Unexpected payment status: {result.status}")
    if quantize_money(result.amount) != quantize_money(amount):
        raise PaymentError("Charged amount mismatch.")
    return result


