def checkout(
    *,
    user: User,
    cart_items: Iterable[Dict[str, Any]] | Iterable[CartItem],
    currency: str,
    discount_codes: Optional[Iterable[str]],
    destination: Dict[str, Any],
    payment_method: PaymentMethod,
    inventory: InventoryService,
    discounts: DiscountService,
    tax_service: TaxService,
    payment_gateway: PaymentGateway,
    order_repo: OrderRepository,
    idempotency_key: Optional[str] = None,
    order_metadata: Optional[Dict[str, Any]] = None,
) -> CheckoutResult:
    validated = validate_cart_items(cart_items=cart_items, currency=currency, inventory=inventory)
    disc_res = apply_discount_codes(user=user, validated_cart=validated, discount_codes=discount_codes, discounts=discounts)
