    pay_res = process_payment(user=user, tax_result=tax_res, currency=currency, payment_method=payment_method, payment_gateway=payment_gateway, idempotency_key=idempotency_key)
    order = create_order_record(
        user=user,
        validated_cart=validated,
        discount_result=disc_res,
        tax_result=tax_res,
        payment_result=pay_res,
        order_repo=order_repo,
        metadata=order_metadata,
    )
    return CheckoutResult(
        validated_cart=validated,
        discount_result=disc_res,
        tax_result=tax_res,
        payment_result=pay_res,
        order=order,
    )